#include <iostream>
#include <omp.h>

#define N 1024
#define STEPS 1000

int main() {
    float u[N][N];
    float u_new[N][N];

    // Initialize u with some values (e.g., 0)
    #pragma omp parallel for collapse(2)
    for(int i = 0; i < N; ++i)
        for(int j = 0; j < N; ++j)
            u[i][j] = 0.0f;

    // Main time-stepping loop
    for (int t = 0; t < STEPS; ++t) {
        #pragma omp parallel for collapse(2)
        for (int i = 1; i < N - 1; i++) {
            for (int j = 1; j < N - 1; j++) {
                u_new[i][j] = 0.25f * (u[i+1][j] + u[i-1][j] + u[i][j+1] + u[i][j-1]);
            }
        }

        // Swap pointers or copy new to old
        #pragma omp parallel for collapse(2)
        for (int i = 1; i < N - 1; i++) {
            for (int j = 1; j < N - 1; j++) {
                u[i][j] = u_new[i][j];
            }
        }
    }

    // Output final value at center
    std::cout << "Center value: " << u[N/2][N/2] << std::endl;

    return 0;
}
